// ==UserScript==
// @name         雨课堂字体混淆反混淆
// @namespace    yuketang-font-deobfuscator
// @version      1.0.0
// @description  实时解析雨课堂字体混淆，使用户可以复制到所显示文字
// @author       GLM-5.1 & DeepSeek-V4-Pro in Trae CN
// @homepageURL  https://github.com/novob/yuketang-deobfuscator
// @downloadURL  https://scriptcat.org/scripts/code/6533/%E9%9B%A8%E8%AF%BE%E5%A0%82%E5%AD%97%E4%BD%93%E6%B7%B7%E6%B7%86%E5%8F%8D%E6%B7%B7%E6%B7%86.user.js
// @match        *://*.yuketang.cn/*
// @grant        GM_xmlhttpRequest
// @grant        GM_registerMenuCommand
// @grant        GM_unregisterMenuCommand
// @grant        GM_getValue
// @grant        GM_setValue
// @connect      *
// @require      https://cdn.jsdelivr.net/npm/opentype.js@1.3.4/dist/opentype.min.js
// @run-at       document-start
// ==/UserScript==

    const MAP_DATA = "";

(function() {
    'use strict';

    const CJK_START = 0x4E00;
    const CJK_END = 0x9FFF;
    const CODE_BASE = 0x3400;
    const DECRYPT_FONT_FAMILY = 'exam-data-decrypt-font';

    let hashMap = null;
    let decryptMapping = null;
    let isProcessing = false;
    let deobfEnabled = GM_getValue('deobfEnabled', true);
    let fontDisabled = GM_getValue('fontDisabled', true);
    let originalTextSnapshots = new WeakMap();

    /* 解码内嵌映射表 */
    function decodeMapData(b64) {
        const raw = atob(b64);
        const bytes = new Uint8Array(raw.length);
        for (let i = 0; i < raw.length; i++) bytes[i] = raw.charCodeAt(i);
        const ds = new DecompressionStream('gzip');
        const writer = ds.writable.getWriter();
        writer.write(bytes);
        writer.close();
        return new Response(ds.readable).arrayBuffer().then(function(ab) {
            const buf = new Uint8Array(ab);
            const map = {};
            for (let i = 0; i + 10 < buf.length; i += 11) {
                let hash = '';
                for (let j = 0; j < 8; j++) {
                    hash += buf[i + j].toString(16).padStart(2, '0');
                }
                const delta = (buf[i + 8] << 16) | (buf[i + 9] << 8) | buf[i + 10];
                map[hash] = delta + CODE_BASE;
            }
            return map;
        });
    }

    /* 字形 path.commands → SHA-1 前8字节 (16 hex) */
    function hashCommands(pathCommands) {
        let strToBeHashed = '';
        for (let i = 0; i < pathCommands.length; i++) {
            let sortedCommand = Object.entries(pathCommands[i]).sort(function(a, b) {
                if (a[0] !== b[0]) return a[0] < b[0] ? -1 : 1;
                return a[1] < b[1] ? -1 : 1;
            });
            for (let kv of sortedCommand) {
                strToBeHashed += (kv[0].toString() + kv[1].toString());
            }
        }
        const data = new TextEncoder().encode(strToBeHashed);
        return crypto.subtle.digest('SHA-1', data).then(function(buf) {
            const bytes = new Uint8Array(buf);
            let hash = '';
            for (let i = 0; i < 8; i++) {
                hash += bytes[i].toString(16).padStart(2, '0');
            }
            return hash;
        });
    }

    /* 从 DOM 中提取混淆字体 URL */
    function getObfuscatedFontUrl() {
        const styleElems = document.querySelectorAll('style');
        for (let s of styleElems) {
            if (/font-family:\s*["']exam-data-decrypt-font["']/.test(s.innerHTML)) {
                const matches = s.innerHTML.match(/url\(["']?(.+?)["']?\)/);
                if (matches) return matches[1];
            }
        }
        try {
            for (let sheet of document.styleSheets) {
                try {
                    for (let rule of sheet.cssRules) {
                        if (rule instanceof CSSFontFaceRule) {
                            const src = rule.style.src || '';
                            if (src.includes('exam_font')) {
                                const m = src.match(/url\(["']?(.+?)["']?\)/);
                                if (m) return m[1];
                            }
                        }
                    }
                } catch(e) {}
            }
        } catch(e) {}
        return null;
    }

    /* 下载并解析混淆字体 */
    async function loadExamFont(url) {
        return new Promise(function(resolve, reject) {
            GM_xmlhttpRequest({
                method: 'GET',
                url: url,
                responseType: 'arraybuffer',
                onload: function(resp) {
                    if (resp.status === 200) {
                        try {
                            resolve(opentype.parse(resp.response));
                        } catch(e) {
                            reject(e);
                        }
                    } else {
                        reject(new Error('HTTP ' + resp.status));
                    }
                },
                onerror: reject
            });
        });
    }

    /* 建立混淆码点→原码点映射 */
    async function buildMapping(examFont) {
        const mapping = {};
        let matched = 0, unmatched = 0;
        for (let i = 0; i < examFont.glyphs.length; i++) {
            const g = examFont.glyphs.get(i);
            if (!g.unicodes || g.unicodes.length === 0) continue;
            const codePoint = g.unicodes[0];
            if (codePoint < CJK_START || codePoint > CJK_END) continue;
            const hash = await hashCommands(g.path.commands);
            const originalCode = hashMap[hash];
            if (originalCode !== undefined) {
                mapping[codePoint] = originalCode;
                matched++;
            } else {
                unmatched++;
            }
        }
        console.log('[反混淆] 匹配:', matched, '未匹配:', unmatched);
        return mapping;
    }

    let overrideStyleEl = null;

    /* 收集 @font-face 规则中与 exam_font 相关的信息 */
    function collectFontFaceRules() {
        let lines = [];
        let found = 0;
        try {
            for (let si = 0; si < document.styleSheets.length; si++) {
                const sheet = document.styleSheets[si];
                try {
                    for (let ri = 0; ri < sheet.cssRules.length; ri++) {
                        const rule = sheet.cssRules[ri];
                        if (rule instanceof CSSFontFaceRule) {
                            const src = rule.style.src || '';
                            if (src.includes('exam_font')) {
                                found++;
                                lines.push('@font-face exam_font: src=' + src.substring(0, 200) +
                                    ' unicode-range=' + (rule.style.unicodeRange || '(未设置)'));
                            }
                        }
                    }
                } catch(e) {}
            }
        } catch(e) {}
        if (found === 0) lines.push('未找到 exam_font @font-face 规则');
        return lines.join('\n');
    }

    /* 收集包含混淆字体的 <style> 元素信息 */
    function collectStyleElements() {
        let lines = [];
        const styleElems = document.querySelectorAll('style');
        let found = 0;
        for (let i = 0; i < styleElems.length; i++) {
            const s = styleElems[i];
            if (/exam-data-decrypt-font|exam_font/.test(s.innerHTML)) {
                found++;
                lines.push(
                    '[Style #' + i + '] disabled=' + s.disabled +
                    ' id=' + (s.id || '(无)') +
                    ' len=' + s.innerHTML.length +
                    ' preview=' + s.innerHTML.replace(/\s+/g, ' ').substring(0, 200)
                );
            }
        }
        lines.push('共 ' + found + ' 个包含混淆字体的 style（总计 ' + styleElems.length + ' 个）');
        return lines.join('\n');
    }

    /* 收集 document.fonts 中 exam-data-decrypt-font 的状态 */
    function collectDocumentFonts() {
        let lines = [];
        let found = 0;
        document.fonts.forEach(function(f) {
            if (f.family && f.family.includes('exam-data-decrypt-font')) {
                found++;
                lines.push('document.fonts[' + found + ']: status=' + f.status +
                    ' weight=' + f.weight + ' style=' + f.style);
            }
        });
        if (found === 0) lines.push('document.fonts 中无 exam-data-decrypt-font');
        return lines.join('\n');
    }

    /* 收集使用混淆字体的元素信息 */
    function collectElementsUsingFont() {
        let lines = [];
        let found = 0;
        function walkAndCheck(node) {
            if (node.nodeType === Node.TEXT_NODE) {
                const text = node.textContent;
                if (text.trim().length === 0) return;
                const parent = node.parentElement;
                if (!parent) return;
                const computed = getComputedStyle(parent);
                const ff = computed.fontFamily;
                if (ff.includes('exam-data-decrypt-font') || ff.includes('exam_font')) {
                    found++;
                    if (found <= 20) {
                        lines.push(
                            '[#' + found + '] ' + parent.tagName +
                            ' class=' + (parent.className?.toString() || '').substring(0, 60) +
                            ' text=' + text.substring(0, 40)
                        );
                    }
                }
            } else if (node.nodeType === Node.ELEMENT_NODE) {
                for (let child of node.childNodes) {
                    walkAndCheck(child);
                }
            }
        }
        walkAndCheck(document.body);
        lines.push('共 ' + found + ' 个元素使用 exam-data-decrypt-font');
        return lines.join('\n');
    }

    /* 收集混淆元素的父级 DOM 结构，用于分析选项/题目的组织方式 */
    function collectOptionHierarchy() {
        let lines = [];
        const elems = document.querySelectorAll('.xuetangx-com-encrypted-font');
        if (elems.length === 0) {
            lines.push('无 .xuetangx-com-encrypted-font 元素');
            return lines.join('\n');
        }
        lines.push('共 ' + elems.length + ' 个 .xuetangx-com-encrypted-font，前 15 个的祖先链:');
        const max = Math.min(15, elems.length);
        for (let i = 0; i < max; i++) {
            const el = elems[i];
            const text = el.textContent.substring(0, 30);
            /* 向上遍历祖先，收集标签、类名、id */
            let chain = [];
            let cur = el;
            let depth = 0;
            while (cur && cur !== document.body && depth < 10) {
                let desc = cur.tagName;
                if (cur.id) desc += '#' + cur.id;
                if (cur.className && typeof cur.className === 'string') {
                    const cls = cur.className.split(' ').filter(function(c) {
                        return c && c !== 'xuetangx-com-encrypted-font';
                    }).slice(0, 3).join('.');
                    if (cls) desc += '.' + cls;
                }
                /* 检查是否有 role、data-* 等属性 */
                const role = cur.getAttribute('role');
                if (role) desc += '[role=' + role + ']';
                const dataType = cur.getAttribute('data-type');
                if (dataType) desc += '[data-type=' + dataType + ']';
                chain.unshift(desc);
                cur = cur.parentElement;
                depth++;
            }
            lines.push('  [' + (i + 1) + '] text="' + text + '" chain: ' + chain.join(' > '));
        }
        return lines.join('\n');
    }

    /* 完整诊断：收集所有信息并通过浏览器下载 */
    function runDiagnostics() {
        let report = [];
        report.push('========== 反混淆诊断报告 ==========');
        report.push('时间: ' + new Date().toISOString());
        report.push('URL: ' + window.location.href);
        report.push('');
        report.push('--- 状态 ---');
        report.push('deobfEnabled: ' + deobfEnabled);
        report.push('fontDisabled: ' + fontDisabled);
        report.push('overrideStyleEl: ' + (overrideStyleEl ? '已注入' : '未注入'));
        report.push('decryptMapping: ' + (decryptMapping ? '已建立（' + Object.keys(decryptMapping).length + ' 条）' : '未建立'));
        report.push('fontUrlRetryTimer: ' + (fontUrlRetryTimer ? '运行中' : '未运行'));
        report.push('');
        report.push('--- @font-face ---');
        report.push(collectFontFaceRules());
        report.push('');
        report.push('--- <style> 元素 ---');
        report.push(collectStyleElements());
        report.push('');
        report.push('--- document.fonts ---');
        report.push(collectDocumentFonts());
        report.push('');
        report.push('--- 混淆元素 ---');
        report.push(collectElementsUsingFont());
        report.push('');
        report.push('--- 选项层级 ---');
        report.push(collectOptionHierarchy());
        report.push('');
        report.push('--- 页面结构 ---');
        report.push(dumpPageStructure());
        report.push('');
        report.push('========== 诊断结束 ==========');

        const text = report.join('\n');
        const blob = new Blob([text], { type: 'text/plain;charset=utf-8' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = 'yuketang-deobf-diagnostic-' + new Date().toISOString().replace(/[:.]/g, '-') + '.txt';
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
    }

    /* 禁用混淆字体 @font-face，使文本回退到系统字体 */
    function disableObfuscatedFont() {
        /* 先清理上一次的覆盖样式，防止重复累积 */
        if (overrideStyleEl) {
            overrideStyleEl.remove();
            overrideStyleEl = null;
        }
        console.log('[反混淆] 开始禁用混淆字体...');

        /* 方案A：注入覆盖 @font-face，将 src 指向不存在的本地字体 */
        overrideStyleEl = document.createElement('style');
        overrideStyleEl.id = 'deobf-font-override';
        overrideStyleEl.textContent = [
            '@font-face {',
            '  font-family: "exam-data-decrypt-font";',
            '  src: local("DeobfDisabledPlaceholder") !important;',
            '  unicode-range: U+0-10FFFF;',
            '}'
        ].join('\n');
        document.head.appendChild(overrideStyleEl);
        console.log('[反混淆] 方案A：已注入覆盖 @font-face');

        /* 方案B：禁用包含混淆字体的 <style> 元素 */
        let disabledCount = 0;
        const styleElems = document.querySelectorAll('style');
        for (let s of styleElems) {
            if (s.id === 'deobf-font-override') continue;
            if (/font-family:\s*["']exam-data-decrypt-font["']/.test(s.innerHTML)) {
                s.disabled = true;
                disabledCount++;
            }
        }
        console.log('[反混淆] 方案B：已禁用', disabledCount, '个 <style> 元素');

        /* 方案C：从 document.fonts 中删除已加载的混淆字体 */
        if (document.fonts && document.fonts.delete) {
            let fontDeleted = 0;
            document.fonts.forEach(function(f) {
                if (f.family && f.family.includes('exam-data-decrypt-font')) {
                    try {
                        document.fonts.delete(f);
                        fontDeleted++;
                    } catch(e) {}
                }
            });
            if (fontDeleted > 0) {
                console.log('[反混淆] 方案C：已从 document.fonts 删除', fontDeleted, '个字体');
            }
        }
    }

    /* 恢复混淆字体 @font-face */
    function enableObfuscatedFont() {
        if (overrideStyleEl) {
            overrideStyleEl.remove();
            overrideStyleEl = null;
        }
        /* 重新启用被禁用但包含混淆字体声明的 <style> 元素 */
        const styleElems = document.querySelectorAll('style');
        for (let s of styleElems) {
            if (s.id === 'deobf-font-override') continue;
            if (/font-family:\s*["']exam-data-decrypt-font["']/.test(s.innerHTML)) {
                s.disabled = false;
            }
        }
        console.log('[反混淆] 已恢复混淆字体');
    }

    /* 查找当前 DOM 中使用混淆字体的元素
     * 优先通过类名 .xuetangx-com-encrypted-font 查找，回退到检查 computed font-family */
    function findObfuscatedElements() {
        const byClass = document.querySelectorAll('.xuetangx-com-encrypted-font');
        if (byClass.length > 0) {
            return new Set(byClass);
        }
        /* 回退：遍历所有元素，检查 computed font-family 是否包含 exam-data-decrypt-font */
        const elements = new Set();
        const all = document.querySelectorAll('*');
        for (const el of all) {
            try {
                if (getComputedStyle(el).fontFamily.includes(DECRYPT_FONT_FAMILY)) {
                    elements.add(el);
                }
            } catch(e) {}
        }
        return elements;
    }

    /* 替换 DOM 中的混淆文本，保存原始文本用于恢复
     * obfuscatedElements: Set<Element> 使用混淆字体的元素集合，仅替换这些元素内的文本 */
    function replaceObfuscatedText(mapping, obfuscatedElements) {
        let replacedCount = 0;
        function walkTextNodes(node) {
            if (node.nodeType === Node.TEXT_NODE) {
                if (originalTextSnapshots.has(node)) return;
                const parent = node.parentElement;
                if (!parent) return;
                /* 仅替换使用混淆字体的元素内的文本，避免误改正常文本 */
                let isObfuscated = false;
                let el = parent;
                while (el) {
                    if (obfuscatedElements.has(el)) {
                        isObfuscated = true;
                        break;
                    }
                    el = el.parentElement;
                }
                if (!isObfuscated) return;
                let text = node.textContent;
                let changed = false;
                let result = '';
                for (const ch of text) {
                    const code = ch.codePointAt(0);
                    if (mapping[code] !== undefined) {
                        result += String.fromCodePoint(mapping[code]);
                        changed = true;
                    } else {
                        result += ch;
                    }
                }
                if (changed) {
                    originalTextSnapshots.set(node, text);
                    node.textContent = result;
                    replacedCount++;
                }
            } else {
                for (let child of node.childNodes) {
                    walkTextNodes(child);
                }
            }
        }
        walkTextNodes(document.body);
        return replacedCount;
    }

    /* 恢复原始文本 */
    function restoreOriginalText() {
        function walkTextNodes(node) {
            if (node.nodeType === Node.TEXT_NODE) {
                const original = originalTextSnapshots.get(node);
                if (original !== undefined) {
                    node.textContent = original;
                    originalTextSnapshots.delete(node);
                }
            } else {
                for (let child of node.childNodes) {
                    walkTextNodes(child);
                }
            }
        }
        walkTextNodes(document.body);
    }

    /* 主流程 */
    let fontUrlRetryTimer = null;

    async function main() {
        if (isProcessing) return;
        isProcessing = true;
        try {
            if (!hashMap) {
                console.log('[反混淆] 解码映射表...');
                hashMap = await decodeMapData(MAP_DATA);
                console.log('[反混淆] 映射表已加载:', Object.keys(hashMap).length, '条');
            }
            const fontUrl = getObfuscatedFontUrl();
            if (!fontUrl) {
                console.log('[反混淆] 未找到混淆字体，启动轮询重试...');
                startFontUrlRetry();
                return;
            }
            /* 找到字体后停止轮询 */
            stopFontUrlRetry();
            console.log('[反混淆] 混淆字体 URL:', fontUrl);
            const examFont = await loadExamFont(fontUrl);
            console.log('[反混淆] 混淆字体已加载');
            decryptMapping = await buildMapping(examFont);
            /* 在禁用字体前查找使用混淆字体的元素，此时 computed font-family 仍为原始值 */
            const obfuscatedElements = findObfuscatedElements();
            console.log('[反混淆] 找到', obfuscatedElements.size, '个使用混淆字体的元素');
            if (fontDisabled) {
                disableObfuscatedFont();
            }
            if (deobfEnabled) {
                const count = replaceObfuscatedText(decryptMapping, obfuscatedElements);
                console.log('[反混淆] 替换完成，共替换', count, '个文本节点');
            }
        } catch(e) {
            console.error('[反混淆] 错误:', e);
        } finally {
            isProcessing = false;
        }
    }

    /* 轮询重试查找混淆字体 URL，解决页面动态注入样式导致初次查找失败 */
    function startFontUrlRetry() {
        if (fontUrlRetryTimer) return;
        let attempts = 0;
        fontUrlRetryTimer = setInterval(function() {
            attempts++;
            const fontUrl = getObfuscatedFontUrl();
            if (fontUrl) {
                stopFontUrlRetry();
                console.log('[反混淆] 轮询第', attempts, '次找到混淆字体');
                main();
            } else if (attempts >= 30) {
                stopFontUrlRetry();
                console.log('[反混淆] 轮询超时，未找到混淆字体');
            }
        }, 500);
    }

    function stopFontUrlRetry() {
        if (fontUrlRetryTimer) {
            clearInterval(fontUrlRetryTimer);
            fontUrlRetryTimer = null;
        }
    }

    /* 切换反混淆（替换文本） */
    function toggleDeobfuscation() {
        deobfEnabled = !deobfEnabled;
        GM_setValue('deobfEnabled', deobfEnabled);
        if (deobfEnabled) {
            if (decryptMapping) {
                const obfuscatedElements = findObfuscatedElements();
                replaceObfuscatedText(decryptMapping, obfuscatedElements);
            } else {
                main();
            }
        } else {
            restoreOriginalText();
        }
        registerMenuCommands();
    }

    /* 切换禁用混淆字体 */
    function toggleFontDisable() {
        fontDisabled = !fontDisabled;
        GM_setValue('fontDisabled', fontDisabled);
        if (fontDisabled) {
            disableObfuscatedFont();
        } else {
            enableObfuscatedFont();
        }
        registerMenuCommands();
    }

    /* 注册脚本管理器菜单命令，仅在顶层窗口注册，避免 iframe 重复触发 */
    let menuIds = [];
    function registerMenuCommands() {
        if (window.top !== window.self) return;
        for (const id of menuIds) {
            GM_unregisterMenuCommand(id);
        }
        menuIds = [
            GM_registerMenuCommand(
                deobfEnabled ? '✅ 反混淆：已开启' : '⬜ 反混淆：已关闭',
                toggleDeobfuscation,
                'd'
            ),
            GM_registerMenuCommand(
                fontDisabled ? '✅ 禁用混淆字体：已开启' : '⬜ 禁用混淆字体：已关闭',
                toggleFontDisable,
                'f'
            ),
            GM_registerMenuCommand(
                '🔍 诊断：下载字体调试报告',
                runDiagnostics,
                'x'
            )
        ];
    }

    /* 判断文本节点是否处于混淆元素内部 */
    function isInsideObfuscatedElement(node) {
        let el = node.parentElement;
        while (el) {
            if (el.classList && el.classList.contains('xuetangx-com-encrypted-font')) {
                return true;
            }
            try {
                if (getComputedStyle(el).fontFamily.includes(DECRYPT_FONT_FAMILY)) {
                    return true;
                }
            } catch(e) {}
            el = el.parentElement;
        }
        return false;
    }

    /* 处理单个文本节点中的混淆字符，返回替换数量 */
    function processSingleTextNode(node, mapping) {
        if (originalTextSnapshots.has(node)) return 0;
        let text = node.textContent;
        let changed = false;
        let result = '';
        for (const ch of text) {
            const code = ch.codePointAt(0);
            if (mapping[code] !== undefined) {
                result += String.fromCodePoint(mapping[code]);
                changed = true;
            } else {
                result += ch;
            }
        }
        if (changed) {
            originalTextSnapshots.set(node, text);
            node.textContent = result;
            return 1;
        }
        return 0;
    }

    /* 监听 DOM 变化 */
    let mutationStats = { total: 0, childList: 0, attributes: 0, characterData: 0, skipped: 0 };
    const observer = new MutationObserver(function(mutations) {
        mutationStats.total++;
        console.log('[反混淆调试] --- MutationObserver 触发 #' + mutationStats.total + ' ---');
        console.log('[反混淆调试] 本次 mutation 记录数:', mutations.length);
        if (!deobfEnabled && !fontDisabled) {
            mutationStats.skipped++;
            console.log('[反混淆调试] 跳过：两个功能均关闭');
            return;
        }
        let hasFontChange = false;
        let hasNewObfuscatedContent = false;
        for (const mutation of mutations) {
            console.log('[反混淆调试] Mutation 类型:', mutation.type,
                '目标:', (mutation.target.tagName || 'text') +
                (mutation.target.id ? '#' + mutation.target.id : '') +
                (mutation.target.className ? '.' + (typeof mutation.target.className === 'string' ? mutation.target.className.split(' ')[0] : '') : ''));
            /* characterData：文本节点内容变化，即时逐字处理 */
            if (mutation.type === 'characterData') {
                mutationStats.characterData++;
                console.log('[反混淆调试]   文本变化:', mutation.target.textContent.substring(0, 50));
                if (decryptMapping && deobfEnabled && !originalTextSnapshots.has(mutation.target)) {
                    if (isInsideObfuscatedElement(mutation.target)) {
                        console.log('[反混淆调试]   -> 混淆元素内文本变化，即时处理');
                        processSingleTextNode(mutation.target, decryptMapping);
                    }
                }
                continue;
            }
            /* childList：新增/移除节点 */
            if (mutation.type === 'childList') {
                mutationStats.childList++;
                console.log('[反混淆调试]   addedNodes:', mutation.addedNodes.length, 'removedNodes:', mutation.removedNodes.length);
                for (const node of mutation.addedNodes) {
                    if (node.nodeType === Node.ELEMENT_NODE) {
                        const tagInfo = '<' + node.tagName +
                            (node.id ? ' id=' + node.id : '') +
                            (node.className && typeof node.className === 'string' ? ' class=' + node.className.substring(0, 50) : '') +
                            '>';
                        console.log('[反混淆调试]   新增元素:', tagInfo);
                        if (node.tagName === 'STYLE'
                            || (node.tagName === 'LINK' && node.rel === 'stylesheet')
                            || node.querySelector('style, link[rel="stylesheet"]')) {
                            hasFontChange = true;
                            console.log('[反混淆调试]   -> 检测到样式表变更');
                        }
                        if (!hasNewObfuscatedContent) {
                            if (node.classList && node.classList.contains('xuetangx-com-encrypted-font')
                                || node.querySelector('.xuetangx-com-encrypted-font')) {
                                hasNewObfuscatedContent = true;
                                console.log('[反混淆调试]   -> 检测到新增混淆元素');
                            }
                        }
                    } else if (node.nodeType === Node.TEXT_NODE && node.textContent.trim().length > 0) {
                        console.log('[反混淆调试]   新增文本:', node.textContent.substring(0, 50));
                    }
                }
            }
            /* attributes */
            if (mutation.type === 'attributes') {
                mutationStats.attributes++;
                console.log('[反混淆调试]   属性变化:', mutation.attributeName,
                    '旧值:', mutation.oldValue,
                    '新值:', mutation.target.getAttribute(mutation.attributeName));
            }
            if (mutation.type === 'attributes' && mutation.attributeName === 'disabled') {
                if (mutation.target.tagName === 'STYLE'
                    && mutation.target.disabled === false
                    && /font-family:\s*["']exam-data-decrypt-font["']/.test(mutation.target.innerHTML)) {
                    hasFontChange = true;
                    console.log('[反混淆调试]   -> 检测到混淆字体样式被重新启用');
                }
            }
        }
        console.log('[反混淆调试] hasFontChange:', hasFontChange, 'hasNewObfuscatedContent:', hasNewObfuscatedContent);
        if (hasFontChange) {
            let isSelfTriggered = false;
            for (const mutation of mutations) {
                for (const node of mutation.addedNodes) {
                    if (node.nodeType === Node.ELEMENT_NODE && node.id === 'deobf-font-override') {
                        isSelfTriggered = true;
                        break;
                    }
                }
                if (isSelfTriggered) break;
            }
            console.log('[反混淆调试] isSelfTriggered:', isSelfTriggered);
            if (!isSelfTriggered) {
                if (!decryptMapping) {
                    console.log('[反混淆调试] -> 触发 main() 重建映射');
                    main();
                } else if (fontDisabled) {
                    console.log('[反混淆调试] -> 触发 disableObfuscatedFont()');
                    disableObfuscatedFont();
                }
            }
        }
        /* 新增混淆元素时立即扫描替换，无延迟，MutationObserver 回调在微任务中执行，早于浏览器绘制 */
        if (decryptMapping && deobfEnabled && hasNewObfuscatedContent) {
            console.log('[反混淆调试] 立即扫描替换（无延迟）');
            const obfuscatedElements = findObfuscatedElements();
            const count = replaceObfuscatedText(decryptMapping, obfuscatedElements);
            console.log('[反混淆调试] 替换完成，共替换', count, '个文本节点');
        }
        console.log('[反混淆调试] --- MutationObserver 处理完成 ---');
    });

    /* 打印页面结构摘要 */
    function dumpPageStructure() {
        let lines = [];
        lines.push('title: ' + document.title);
        /* 统计标签分布 */
        let tagCounts = {};
        const all = document.querySelectorAll('*');
        for (const el of all) {
            const tag = el.tagName;
            tagCounts[tag] = (tagCounts[tag] || 0) + 1;
        }
        lines.push('总元素数: ' + all.length);
        let sorted = Object.entries(tagCounts).sort(function(a, b) { return b[1] - a[1]; });
        lines.push('标签分布: ' + sorted.slice(0, 15).map(function(e) { return e[0] + ':' + e[1]; }).join(', '));
        /* 关键类名统计 */
        lines.push('.xuetangx-com-encrypted-font: ' + document.querySelectorAll('.xuetangx-com-encrypted-font').length);
        /* MutationObserver 统计 */
        lines.push('MutationObserver: 总触发=' + mutationStats.total +
            ' childList=' + mutationStats.childList +
            ' attributes=' + mutationStats.attributes +
            ' characterData=' + mutationStats.characterData +
            ' 跳过=' + mutationStats.skipped);
        return lines.join('\n');
    }

    /* SPA 路由变化时触发扫描，延迟 0ms 仅用于让出当前执行栈，实际由 MutationObserver 即时处理 */
    function onRouteChange() {
        console.log('[反混淆调试] >>> 路由变化检测 <<<');
        console.log('[反混淆调试] 新 URL:', window.location.href);
        console.log('[反混淆调试] decryptMapping:', decryptMapping ? '已建立' : '未建立');
        console.log('[反混淆调试] deobfEnabled:', deobfEnabled);
        if (!decryptMapping || !deobfEnabled) {
            console.log('[反混淆调试] 跳过：映射未建立或反混淆未开启');
            return;
        }
        setTimeout(function() {
            console.log('[反混淆调试] 路由变化后扫描...');
            const obfuscatedElements = findObfuscatedElements();
            console.log('[反混淆调试] 找到', obfuscatedElements.size, '个混淆元素');
            const count = replaceObfuscatedText(decryptMapping, obfuscatedElements);
            console.log('[反混淆调试] 替换完成，共替换', count, '个文本节点');
        }, 0);
    }

    /* 拦截 history.pushState / replaceState */
    const _pushState = history.pushState;
    history.pushState = function() {
        console.log('[反混淆调试] history.pushState 被调用');
        _pushState.apply(this, arguments);
        onRouteChange();
    };
    const _replaceState = history.replaceState;
    history.replaceState = function() {
        console.log('[反混淆调试] history.replaceState 被调用');
        _replaceState.apply(this, arguments);
        onRouteChange();
    };
    window.addEventListener('popstate', function() {
        console.log('[反混淆调试] popstate 事件触发');
        onRouteChange();
    });

    setTimeout(function() {
        if (!document.body) {
            setTimeout(arguments.callee, 100);
            return;
        }
        registerMenuCommands();
        observer.observe(document.body, {
            childList: true,
            subtree: true,
            attributes: true,
            attributeFilter: ['disabled'],
            characterData: true,
            characterDataOldValue: false
        });
        console.log('[反混淆调试] MutationObserver 已启动，监听: childList + attributes + characterData');
        main();
    }, 1000);
    console.log('[反混淆] 脚本已加载');
})();

